#include <array>
#include <iostream>

enum Day { Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday, NumDays };

int main() {
    std::array<int, NumDays> temps{};

    for (std::size_t i = 0; i < NumDays; ++i) {
        std::cin >> temps[i];
    }

    const std::array<const char*, NumDays> names{
        "Monday", "Tuesday", "Wednesday", "Thursday",
        "Friday", "Saturday", "Sunday"
    };

    for (std::size_t i = 0; i < NumDays; ++i) {
        std::cout << names[i] << ": " << temps[i] << '\n';
    }

    return 0;
}

