#include <array>
#include <iostream>

enum class Stat { Strength, Dexterity, Constitution, Intelligence, Count };

constexpr std::size_t statIdx(Stat s) {
    return static_cast<std::size_t>(s);
}

int getStat(const std::array<int, statIdx(Stat::Count)>& stats, Stat which) {
    return stats[statIdx(which)];
}

int main() {
    std::array<int, statIdx(Stat::Count)> stats{};
    for (std::size_t i = 0; i < statIdx(Stat::Count); ++i) {
        std::cin >> stats[i];
    }
    int query{};
    std::cin >> query;
    Stat which = static_cast<Stat>(query);
    std::cout << "Stat value: " << getStat(stats, which) << '\n';
    return 0;
}
